// Continue backfill for rows created after the bulk import
// Run with: npx tsx scripts/backfill-tinybird-continue.ts
//
// Reads the max created_at from prompt_runs.meta.json (generated by convert script)

import { readFileSync } from "node:fs";
import { db } from "../src/lib/db/db";
import { prompts, promptRuns } from "../src/lib/db/schema";
import { eq, gt, lte, and, sql } from "drizzle-orm";
import {
	ingestPromptRuns,
	type TinybirdPromptRunEvent,
	type TinybirdCitationItem,
} from "../src/lib/tinybird";
import { extractTextContent, extractCitations } from "../src/lib/text-extraction";

const BATCH_SIZE = 100;
const METADATA_PATH = "./prompt_runs.meta.json";

// Read metadata from the convert script
function getMetadata(): { maxCreatedAt: string; rowCount: number; lastId: string; generatedAt: string } {
	try {
		const content = readFileSync(METADATA_PATH, "utf-8");
		return JSON.parse(content);
	} catch (e: any) {
		if (e.code === "ENOENT") {
			throw new Error(`Metadata file not found: ${METADATA_PATH}\nRun the convert script first: pnpm tsx --env-file=.env scripts/convert-csv-for-tinybird.ts`);
		}
		throw e;
	}
}

async function continueBackfill() {
	const startTime = Date.now();
	const cutoffTime = new Date(); // Only process rows created before this time

	console.log("Tinybird Backfill - Continuation");
	console.log(`  Batch size: ${BATCH_SIZE}`);
	console.log(`  Cutoff time: ${cutoffTime.toISOString()}`);
	console.log("");

	// Read metadata from the convert script
	console.log(`📂 Reading ${METADATA_PATH}...`);
	const metadata = getMetadata();
	const afterCreatedAt = new Date(metadata.maxCreatedAt);
	console.log(`  Max created_at in bulk export: ${afterCreatedAt.toISOString()}`);
	console.log(`  Bulk export row count: ${metadata.rowCount.toLocaleString()}`);
	console.log(`  Metadata generated: ${metadata.generatedAt}`);
	console.log("");

	// Count how many rows need to be processed (between bulk export and cutoff)
	console.log("📊 Counting rows to process...");
	const [countResult] = await db
		.select({ count: sql<number>`count(*)` })
		.from(promptRuns)
		.where(and(gt(promptRuns.createdAt, afterCreatedAt), lte(promptRuns.createdAt, cutoffTime)));
	const estimatedCount = Number(countResult.count);
	console.log(`  Rows to process: ${estimatedCount.toLocaleString()}`);
	console.log("");

	if (estimatedCount === 0) {
		console.log("✅ No new rows to backfill!");
		return;
	}

	console.log("📤 Starting backfill...");

	let lastCreatedAt = afterCreatedAt;
	let totalProcessed = 0;
	let totalQuarantined = 0;

	while (true) {
		const runs = await db
			.select({ run: promptRuns, prompt: prompts })
			.from(promptRuns)
			.innerJoin(prompts, eq(promptRuns.promptId, prompts.id))
			.where(and(gt(promptRuns.createdAt, lastCreatedAt), lte(promptRuns.createdAt, cutoffTime)))
			.orderBy(promptRuns.createdAt, promptRuns.id)
			.limit(BATCH_SIZE);

		if (runs.length === 0) break;

		const events: TinybirdPromptRunEvent[] = runs.map(({ run, prompt }) => {
			const extractedCitations = extractCitations(run.rawOutput, run.modelGroup);
			const citations: TinybirdCitationItem[] = extractedCitations.map((c) => ({
				url: c.url,
				domain: c.domain,
				title: c.title || null,
			}));

			return {
				id: run.id,
				prompt_id: run.promptId,
				brand_id: prompt.brandId,
				model_group: run.modelGroup,
				model: run.model,
				web_search_enabled: run.webSearchEnabled ? 1 : 0,
				brand_mentioned: run.brandMentioned ? 1 : 0,
				competitors_mentioned: run.competitorsMentioned || [],
				web_queries: run.webQueries || [],
				text_content: extractTextContent(run.rawOutput, run.modelGroup),
				raw_output: JSON.stringify(run.rawOutput),
				citations,
				created_at: run.createdAt.toISOString(),
				competitor_count: (run.competitorsMentioned || []).length,
				has_competitor_mention: (run.competitorsMentioned || []).length > 0 ? 1 : 0,
			};
		});

		try {
			const result = await ingestPromptRuns(events);
			totalQuarantined += result.quarantined_rows;
			if (result.quarantined_rows > 0) {
				console.warn(`  ${result.quarantined_rows} quarantined`);
			}
		} catch (error: any) {
			console.error(`\nError at ${lastCreatedAt.toISOString()}: ${error.message}`);
			throw error;
		}

		totalProcessed += events.length;
		lastCreatedAt = runs[runs.length - 1].run.createdAt;

		const elapsed = (Date.now() - startTime) / 1000;
		const rate = Math.round(totalProcessed / elapsed);
		const remaining = estimatedCount - totalProcessed;
		const etaSeconds = rate > 0 ? Math.round(remaining / rate) : 0;
		const etaStr = etaSeconds > 60 ? `${Math.round(etaSeconds / 60)}m` : `${etaSeconds}s`;
		const pct = ((totalProcessed / estimatedCount) * 100).toFixed(1);
		process.stdout.write(`\r  ${totalProcessed.toLocaleString()}/${estimatedCount.toLocaleString()} (${pct}%) | ${rate}/s | ETA: ${etaStr}    `);
	}

	const totalTime = ((Date.now() - startTime) / 1000).toFixed(1);

	console.log(`\n${"=".repeat(50)}`);
	if (totalProcessed === 0) {
		console.log("No new rows found.");
	} else {
		console.log(`Backfilled ${totalProcessed.toLocaleString()} new rows`);
		console.log(`Quarantined: ${totalQuarantined}`);
		console.log(`Time: ${totalTime}s`);
	}
	console.log("=".repeat(50));
	console.log("\nNext: Run verification script to check data integrity:");
	console.log("  pnpm tsx --env-file=.env scripts/verify-tinybird-backfill.ts");
}

continueBackfill()
	.then(() => process.exit(0))
	.catch((e) => {
		console.error("\nFailed:", e);
		process.exit(1);
	});
